client_script:
let isSubmitting = false;

frappe.web_form.validate = async () => {
    if (isSubmitting) {
        frappe.msgprint("Already submitting... please wait");
        return false;
    }

    let user = frappe.web_form.get_value("employee_car_process_form");
    let company = frappe.web_form.get_value("vendor");
    let quotation_id = frappe.web_form.get_value("quotation_form");

    let form_name = "Car Contract Form";
    let contract_number = frappe.web_form.get_value("contract_number");
    let form_status = frappe.web_form.get_value("contract_signed");
    let form_document = frappe.web_form.get_value("upload_contract");
    let form_date = frappe.web_form.get_value("contract_start_date");
    let contract_end_date = frappe.web_form.get_value("contract_end_date");


    // Manual validation to prevent API call and email sending if fields are missing
    if (!company) {
        frappe.msgprint("Please select a Company.");
        return false;
    }
    if (form_status === "Yes") {
        if (!form_date) {
            frappe.msgprint("Please select Contract Start Date.");
            return false;
        }
        if (!contract_end_date) {
            frappe.msgprint("Please select Contract End Date.");
            return false;
        }
        if (!contract_number) {
            frappe.msgprint("Please enter Contract Number.");
            return false;
        }
    }

    if (!form_document) {
        frappe.msgprint("Please attach file before submitting");
        return false;
    }
    try {
        const urlObj = new URL(form_document, window.location.origin);
        form_document = urlObj.pathname;
    } catch (e) {
        console.warn("URL parse failed:", form_document);
    }

    if (!form_document.startsWith("/files/") && !form_document.startsWith("/private/files/")) {
        frappe.msgprint("Invalid file uploaded. Please re-upload.");
        return false;
    }

    isSubmitting = true;
    const btn = $(".web-form-actions .btn-primary");
    btn.prop("disabled", true);
    btn.text("Saving...");

    try {
        const r = await frappe.call({
            method: "alms_app.api.car_process.car_form_fill",
            type: "POST",
            args: { 
                user,
                company,
                quotation_id,
                form_name,
                form_status,
                form_document,
                contract_number,
                form_date,
                contract_end_date
            }
        });

        if (!r.message || r.message.status !== "success") {
            frappe.msgprint({
                title: "Error",
                indicator: "red",
                message: r.message?.message || "Something went wrong"
            });
            return false;
        }
        return true;
    } catch (e) {
        frappe.msgprint({
            title: "Server Error",
            indicator: "red",
            message: "API failed. Please try again."
        });
        return false;
    }
};

frappe.web_form.after_load = () => {
    let params = new URLSearchParams(window.location.search);

    // Auto-populate from URL
    if(params.get('user')) {
        frappe.web_form.set_value('employee_car_process_form', params.get('user'));
        frappe.web_form.set_value('user', params.get('user'));
    }
    if(params.get('company')) {
        frappe.web_form.set_value('vendor', params.get('company'));
    }
    if(params.get('quotation_form')) {
        frappe.web_form.set_value('quotation_form', params.get('quotation_form'));
    }

    // Handle ALD exception for Company field auto-filling
    setTimeout(() => {
        if(params.get('company') === 'ALD') {
            frappe.web_form.set_value('company', '');
        }
    }, 500);
};

frappe.web_form.on('contract_number', (field, value) => {
    let vendor = frappe.web_form.get_value('vendor');
    if (vendor && vendor !== 'ALD' && value) {
        let prefix = value.split('-')[0];
        if (prefix) {
            frappe.web_form.set_value('company', prefix);
        }
    }
});
